// P1-FIX: Input Validation Layer (§4.1 PRE-validate)
// P3-FIX: Webhook auth via x-seed-token header
// P2-FIX: tz_offset validation
// FIX-REGEX: Replace all regex with native JS validation

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const headers = raw.headers || {};

// P3: Auth check — only for webhook calls (have headers)
if (raw.headers && typeof raw.headers === 'object') {
  const token = headers['x-seed-token'] || headers['X-Seed-Token'] || '';
  const expected = $vars?.SEED_AUTH_TOKEN || '';
  if (expected && token !== expected) {
    return [{
      json: {
        success: false,
        error_code: 'AUTH_FAILED',
        error_message: 'Invalid or missing x-seed-token header',
        data: null,
        _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
      }
    }];
  }
}

// === DATE VALIDATION (Native JS, no regex) ===
let date = input.date || new Date().toISOString().split('T')[0];
date = String(date).trim();

// Check format: must be YYYY-MM-DD (4 digits, 2 digits, 2 digits)
const dateParts = date.split('-');
if (dateParts.length !== 3) {
  throw new Error('INVALID_INPUT: date must be YYYY-MM-DD format, got: ' + date.substring(0, 20));
}

const year = Number(dateParts[0]);
const month = Number(dateParts[1]);
const day = Number(dateParts[2]);

// Validate numeric values
if (isNaN(year) || isNaN(month) || isNaN(day)) {
  throw new Error('INVALID_INPUT: date components must be numeric');
}

// Validate ranges
if (year < 1900 || year > 2100) {
  throw new Error('INVALID_INPUT: year must be 1900-2100, got: ' + year);
}
if (month < 1 || month > 12) {
  throw new Error('INVALID_INPUT: month must be 1-12, got: ' + month);
}

// Validate day exists for given month/year (handles Feb 29, 30, 31 correctly)
const dateObj = new Date(year, month - 1, day);
if (dateObj.getFullYear() !== year || dateObj.getMonth() !== month - 1 || dateObj.getDate() !== day) {
  throw new Error('INVALID_INPUT: date does not exist: ' + date);
}

// === PROVIDER_ID VALIDATION (Native JS, no regex) ===
const provider_id = Number(input.provider_id ?? 1);
if (typeof input.provider_id === 'string') {
  const trimmed = input.provider_id.trim();
  if (trimmed === '' || isNaN(Number(trimmed))) {
    throw new Error('INVALID_INPUT: provider_id must be a number');
  }
}
if (isNaN(provider_id) || !Number.isInteger(provider_id) || provider_id < 1) {
  throw new Error('INVALID_INPUT: provider_id must be a positive integer, got: ' + String(input.provider_id));
}

// === SERVICE_ID VALIDATION (Native JS, no regex) ===
const service_id = Number(input.service_id ?? 1);
if (typeof input.service_id === 'string') {
  const trimmed = input.service_id.trim();
  if (trimmed === '' || isNaN(Number(trimmed))) {
    throw new Error('INVALID_INPUT: service_id must be a number');
  }
}
if (isNaN(service_id) || !Number.isInteger(service_id) || service_id < 1) {
  throw new Error('INVALID_INPUT: service_id must be a positive integer, got: ' + String(input.service_id));
}

// === CHAT_ID VALIDATION (Native JS, no regex) ===
const chat_id = Number(input.chat_id ?? 0);
if (typeof input.chat_id === 'string') {
  const trimmed = input.chat_id.trim();
  if (trimmed === '' || isNaN(Number(trimmed))) {
    throw new Error('INVALID_INPUT: chat_id must be a number');
  }
}
if (isNaN(chat_id) || !Number.isInteger(chat_id) || chat_id < 0) {
  throw new Error('INVALID_INPUT: chat_id must be a non-negative integer, got: ' + String(input.chat_id));
}

// === HOURS VALIDATION (Native JS, no regex) ===
let hours = [9, 10, 11, 12, 13, 14, 15, 16];
if (Array.isArray(input.hours)) {
  if (input.hours.length === 0) {
    throw new Error('INVALID_INPUT: hours array cannot be empty');
  }
  if (input.hours.length > 24) {
    throw new Error('INVALID_INPUT: hours array cannot have more than 24 entries');
  }

  hours = input.hours.map((h, idx) => {
    const hour = Number(h);
    if (isNaN(hour) || !Number.isInteger(hour)) {
      throw new Error('INVALID_INPUT: hour at index ' + idx + ' must be an integer, got: ' + String(h));
    }
    if (hour < 0 || hour > 23) {
      throw new Error('INVALID_INPUT: hour must be 0-23, got: ' + hour + ' at index ' + idx);
    }
    return hour;
  });
}

// === DURATION_MINUTES VALIDATION (Native JS, no regex) ===
const duration_minutes = Number(input.duration_minutes ?? 60);
if (typeof input.duration_minutes === 'string') {
  const trimmed = input.duration_minutes.trim();
  if (trimmed === '' || isNaN(Number(trimmed))) {
    throw new Error('INVALID_INPUT: duration_minutes must be a number');
  }
}
if (isNaN(duration_minutes) || !Number.isInteger(duration_minutes)) {
  throw new Error('INVALID_INPUT: duration_minutes must be an integer');
}
if (duration_minutes < 15 || duration_minutes > 480) {
  throw new Error('INVALID_INPUT: duration_minutes must be 15-480, got: ' + duration_minutes);
}

// === TZ_OFFSET VALIDATION (Native JS, no regex) ===
let tz_offset = input.tz_offset || '-03:00';
tz_offset = String(tz_offset).trim();

// Must be in format +HH:MM or -HH:MM
if (tz_offset.length !== 6) {
  throw new Error('INVALID_INPUT: tz_offset must be +HH:MM or -HH:MM, got: ' + tz_offset);
}

const tzSign = tz_offset.charAt(0);
const tzHour = tz_offset.substring(1, 3);
const tzMin = tz_offset.substring(4, 6);

if (tzSign !== '+' && tzSign !== '-') {
  throw new Error('INVALID_INPUT: tz_offset must start with + or -, got: ' + tzSign);
}
if (tz_offset.charAt(3) !== ':') {
  throw new Error('INVALID_INPUT: tz_offset must have : at position 4, got: ' + tz_offset.charAt(3));
}

const tzHourNum = Number(tzHour);
const tzMinNum = Number(tzMin);

if (isNaN(tzHourNum) || isNaN(tzMinNum)) {
  throw new Error('INVALID_INPUT: tz_offset hours and minutes must be numeric');
}
if (tzHourNum < 0 || tzHourNum > 14) {
  throw new Error('INVALID_INPUT: tz_offset hours must be 00-14');
}
if (tzMinNum < 0 || tzMinNum > 59) {
  throw new Error('INVALID_INPUT: tz_offset minutes must be 00-59');
}

return [{ json: { date, provider_id, service_id, chat_id, hours, duration_minutes, tz_offset, _validated: true } }];

// Generate slot items from validated input
// FIX #1: idempotency_key = SEED-{date}-P{pid}-S{sid}-{hour}
// FIX #4 + P2: timestamps with explicit timezone offset
// FIX #9: externalized params
// FIX #10: execution metadata

const v = $input.first().json;
if (!v._validated) throw new Error('PIPELINE_ERROR: unvalidated input reached Generate Slots');

const { date, provider_id, service_id, chat_id, hours, duration_minutes, tz_offset } = v;

$execution.customData.set('seed_date', date);
$execution.customData.set('seed_provider', String(provider_id));
$execution.customData.set('seed_service', String(service_id));
$execution.customData.set('seed_slot_count', String(hours.length));

const dateClean = date.replace(/-/g, '');

return hours.map(hour => {
  const h = String(hour).padStart(2, '0');
  const hNext = String(hour + 1).padStart(2, '0');
  const idempotency_key = `SEED-${dateClean}-P${provider_id}-S${service_id}-${h}00`;
  return {
    json: {
      provider_id,
      service_id,
      start_time: `${date}T${h}:00:00${tz_offset}`,
      end_time: `${date}T${hNext}:00:00${tz_offset}`,
      chat_id,
      idempotency_key,
      duration_minutes,
      source: 'SEED_01'
    }
  };
});

// FIX #8: only onError:continueErrorOutput — no continueOnFail
const err = $input.first().json;
return [{
  json: {
    success: false,
    error_code: 'PROCESS_SLOT_CRASH',
    error_message: err.message || err.error?.message || 'SEED_01_Process_Slot crashed',
    data: { slot: 'unknown', idempotency_key: null, source: 'SEED_01' },
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString() }
  }
}];

// P0-FIX: Integrity check — detect silent data loss
const results = $input.all().map(i => i.json);

const expectedStr = $execution.customData.get('seed_slot_count');
const expected = parseInt(expectedStr || '0');
const booked = results.filter(r => r.success === true);
const failed = results.filter(r => r.success === false);
const total = results.length;

let integrity_status = 'OK';
let integrity_warning = null;
if (expected > 0 && total !== expected) {
  integrity_status = 'SLOT_COUNT_MISMATCH';
  integrity_warning = `Expected ${expected} slots but processed ${total}. Possible silent data loss.`;
}

$execution.customData.set('seed_booked', String(booked.length));
$execution.customData.set('seed_failed', String(failed.length));
$execution.customData.set('seed_integrity', integrity_status);

results.sort((a, b) => (a.slot || '').localeCompare(b.slot || ''));

return [{
  json: {
    success: integrity_status === 'OK' && failed.length === 0,
    error_code: (integrity_status === 'OK' && failed.length === 0) ? null : 'PROVISIONING_ERROR',
    error_message: (integrity_status === 'OK' && failed.length === 0) ? null : 'Some slots failed to provision or integrity warning',
    message: `Seeding completed: ${booked.length} booked, ${failed.length} failed` +
      (integrity_warning ? ` | WARNING: ${integrity_warning}` : ''),
    data: {
      total_slots: total,
      expected_slots: expected,
      booked: booked.length,
      failed: failed.length,
      integrity_status,
      integrity_warning,
      details: results
    },
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }
}];
